// 4-viewport Pepper's-Ghost renderer.
//
// Layout (on a face-up iPad, viewed from above):
//
//             +---+
//             | N |          N = camera facing avatar from +Z, rotated 180° on canvas
//             +---+              so its "up" points toward screen center.
//    +---+    +---+    +---+
//    | W | -- | C | -- | E |    W = -X camera, rotated  +90°
//    +---+    +---+    +---+    E = +X camera, rotated  -90°
//             +---+
//             | S |          S = -Z camera, rotated   0° (upright)
//             +---+
//
// Each pyramid face reflects one viewport upward. The convention "bottom of
// each viewport faces the centre of the canvas" guarantees that after the
// 45° reflection the avatar appears head-up to a viewer standing at that side.
//
// The cleanest way to render this with Three.js is: render four square
// render-targets, then composite them with rotations onto the main canvas
// using a fullscreen 2D pass (`OrthographicCamera` + textured planes).
//
// Background is set to pure BLACK — black pixels reflect almost nothing off
// the acrylic pyramid, so the avatar appears to float in space.

import * as THREE from 'three';

export class PyramidRenderer {
  constructor(canvas, avatarScene) {
    this.canvas = canvas;
    this.avatarScene = avatarScene;
    this.renderer = new THREE.WebGLRenderer({
      canvas, antialias: true, alpha: false, powerPreference: 'high-performance'
    });
    this.renderer.setClearColor(0x000000, 1.0);
    this.renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    this.size = 512;

    // Off-screen RT used for each of the four sub-views.
    this.rt = new THREE.WebGLRenderTarget(this.size, this.size, {
      magFilter: THREE.LinearFilter, minFilter: THREE.LinearFilter
    });

    // Cameras — perspective at four cardinal directions around the avatar.
    const fov = 28, aspect = 1, near = 0.05, far = 50;
    const dist = 2.4;
    const target = () => avatarScene.headTarget;
    this.cams = {
      N: new THREE.PerspectiveCamera(fov, aspect, near, far),
      E: new THREE.PerspectiveCamera(fov, aspect, near, far),
      S: new THREE.PerspectiveCamera(fov, aspect, near, far),
      W: new THREE.PerspectiveCamera(fov, aspect, near, far)
    };
    const place = (cam, x, z) => {
      cam.position.set(x, 0, z);
      cam.lookAt(0, 0, 0); // we shift target into local on render
    };
    place(this.cams.N, 0, +dist);
    place(this.cams.E, +dist, 0);
    place(this.cams.S, 0, -dist);
    place(this.cams.W, -dist, 0);

    // Composite pass: orthographic camera + four planes carrying the four
    // sub-view textures, each rotated correctly.
    this.compScene = new THREE.Scene();
    this.compCam = new THREE.OrthographicCamera(-1, 1, 1, -1, 0, 10);
    this.compCam.position.z = 1;

    // 4 quads, will share a single texture but be drawn in 4 passes so we
    // can swap the texture for each sub-view.
    this.quad = this._makeQuad();
    this.compScene.add(this.quad);

    this.layout = 'pyramid';
    this._onResize = this._onResize.bind(this);
    window.addEventListener('resize', this._onResize);
    this._onResize();
  }

  _makeQuad() {
    const geom = new THREE.PlaneGeometry(1, 1);
    const mat = new THREE.MeshBasicMaterial({ map: this.rt.texture, depthTest: false, depthWrite: false });
    const mesh = new THREE.Mesh(geom, mat);
    return mesh;
  }

  setLayout(layout) { this.layout = layout; }

  _onResize() {
    const w = this.canvas.clientWidth | 0;
    const h = this.canvas.clientHeight | 0;
    this.renderer.setSize(w, h, false);
    // Sub-view square side = min/3 (so 3 of them fit edge-to-edge across).
    const side = Math.floor(Math.min(w, h) / 3);
    if (side > 8 && side !== this.size) {
      this.size = side;
      this.rt.setSize(side, side);
    }
  }

  _renderSubview(cam) {
    this.renderer.setRenderTarget(this.rt);
    this.renderer.clear();
    this.renderer.render(this.avatarScene.scene, cam);
    this.renderer.setRenderTarget(null);
  }

  _drawQuad(centerNDC, sizeNDC, rotationRad) {
    this.quad.position.set(centerNDC.x, centerNDC.y, 0);
    this.quad.scale.set(sizeNDC, sizeNDC, 1);
    this.quad.rotation.z = rotationRad;
    this.renderer.render(this.compScene, this.compCam);
  }

  render() {
    const w = this.renderer.domElement.width;
    const h = this.renderer.domElement.height;
    this.renderer.setClearColor(0x000000, 1.0);
    this.renderer.setViewport(0, 0, w, h);
    this.renderer.setScissor(0, 0, w, h);
    this.renderer.setScissorTest(true);
    this.renderer.clear();

    if (this.layout === 'single') {
      // Debug: just render the front camera fullscreen.
      this.renderer.render(this.avatarScene.scene, this.cams.N);
      return;
    }

    // Side length of each sub-quad in NDC: 2 * (sidePx / shortEdge).
    const shortEdge = Math.min(w, h);
    const sidePx = Math.floor(shortEdge / 3);
    const sideNDC_x = (2 * sidePx) / w;
    const sideNDC_y = (2 * sidePx) / h;
    const sideNDC = Math.min(sideNDC_x, sideNDC_y);

    const draw = (cam, cx, cy, rot) => {
      this._renderSubview(cam);
      this._drawQuad(new THREE.Vector2(cx, cy), sideNDC, rot);
    };

    // Centre offset = sideNDC (one sub-quad away from middle).
    const d = sideNDC;
    // The rotations below assume the quad's local "up" is +Y. We want each
    // viewport's "down" edge to point toward the centre of the canvas.
    draw(this.cams.N,  0,  d,  Math.PI);   // top   – flip 180°
    draw(this.cams.S,  0, -d,  0);         // bottom – upright
    draw(this.cams.E,  d,  0,  Math.PI / 2);   // right – rotate +90°
    draw(this.cams.W, -d,  0, -Math.PI / 2);   // left  – rotate -90°
  }

  dispose() {
    window.removeEventListener('resize', this._onResize);
    this.rt.dispose();
    this.renderer.dispose();
  }
}
